import{_ as c,o as s,c as e,a2 as a}from"./chunks/framework.N6Nd-M9-.js";const g=JSON.parse('{"title":"📋 销售五步详解","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/组长手册/06-销售五步详解.md","filePath":"notes/企业文化/组长手册/06-销售五步详解.md"}'),i={name:"notes/企业文化/组长手册/06-销售五步详解.md"};function l(o,t,n,p,d,r){return s(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="📋-销售五步详解" tabindex="-1">📋 销售五步详解 <a class="header-anchor" href="#📋-销售五步详解" aria-label="Permalink to &quot;📋 销售五步详解&quot;">​</a></h1><blockquote><p>本文将帮助你深入理解相关内容，掌握核心知识。</p></blockquote><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">💡 核心要点</p><p class="tc-body">本文将帮助你深入理解相关内容，掌握核心知识。</p></div><hr><h2 id="📌-01-打招呼" tabindex="-1">📌 01 打招呼 <a class="header-anchor" href="#📌-01-打招呼" aria-label="Permalink to &quot;📌 01 打招呼&quot;">​</a></h2><p class="tc-body" style="font-size:14px;line-height:1.8;"> 打招呼是人际关系开始的第一步，要善用你的亲切、诚恳、自信、热忱的态度去拉近彼此间的距离，别忘了先做朋友，后谈生意的原则。 </p><div class="tc-card tc-card-blue" style="margin-top:15px;"><p class="tc-title tc-blue">💡 三个细节重点</p><p class="tc-body" style="font-size:14px;line-height:1.7;"><strong>[SEX——Smile、Eye-to-eye、Exciting]</strong></p></div><div class="tc-grid tc-grid-auto" style="margin-top:15px;"><div class="tc-card tc-card-green"><p class="tc-title tc-green">😊 一、笑容</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-green tc-body tc-sm">(1) 微笑是国际共通的语言，也是拉近关系、消除敌意的方法；</span><span class="tc-item tc-item-green tc-body tc-sm">(2) 这是一个发自内心的笑容、一种充满自信与愉悦的笑容；</span><span class="tc-item tc-item-green tc-body tc-sm">(3) 没有人会喜欢和一个愁容满面没有微笑的人买东西。</span></div></div><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">👁️ 二、目光</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-blue tc-body tc-sm">(1) 看着对方的眼神，与他目光对接，散发一种吸引人的魅力；</span><span class="tc-item tc-item-blue tc-body tc-sm">(2) 这是一种尊重对方的礼仪；</span><span class="tc-item tc-item-blue tc-body tc-sm">(3) 用你的目光摄住对方。</span></div></div><div class="tc-card tc-card-orange"><p class="tc-title tc-orange">🔥 三、热诚</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-orange tc-body tc-sm">(1) 这是展现自己的自信心；</span><span class="tc-item tc-item-orange tc-body tc-sm">(2) 吸引对方对你的兴趣；</span><span class="tc-item tc-item-orange tc-body tc-sm">(3) 为对方相信你所说的一切赢得信任。</span></div></div></div><p class="tc-body" style="font-size:14px;line-height:1.8;margin-top:15px;"> 打招呼时要善用周围的人、事、时、地、物，可以先寒暄问暖后再切入正题。 </p><div class="tc-container tc-container-blue" style="margin-top:15px;"><p class="tc-subtitle tc-blue">💬 参考说词</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-blue tc-body tc-sm">EX：&quot;哈罗！先生您好！吃饭了吗？&quot;</span><span class="tc-item tc-item-blue tc-body tc-sm">&quot;哈罗！先生您好！在忙呢？&quot;</span><span class="tc-item tc-item-blue tc-body tc-sm">&quot;哈罗！先生您好！哇，你的小孩好可爱喔！&quot;</span><span class="tc-item tc-item-blue tc-body tc-sm">&quot;哇，靓女您的耳环好有品位、您的发型好有型哦，在哪里剪的？&quot;</span><span class="tc-item tc-item-blue tc-body tc-sm">&quot;老板，生意不错吧！&quot;</span><span class="tc-item tc-item-blue tc-body tc-sm">&quot;哇，先生，您的办公室好大气！好气派哦！&quot;</span><span class="tc-item tc-item-blue tc-body tc-sm">&quot;哇，您身材这么好！&quot;</span><span class="tc-item tc-item-blue tc-body tc-sm">&quot;哇，您家装修得真漂亮！&quot;</span></div></div><div class="tc-alert tc-alert-red" style="margin-top:15px;"><p class="tc-body tc-sm" style="margin:0;"><strong>⚠️ 注意：</strong>称呼要灵活多变，根据各个地方风俗来定，一成不变地打招呼方式和过于夸张的寒暄都会令人生厌。发自真诚的赞美和寒暄会令你的招呼立马消融顾客与你的冰墙，可谓无坚不摧。 </p></div><hr><h2 id="🏢-02-介绍自己" tabindex="-1">🏢 02 介绍自己 <a class="header-anchor" href="#🏢-02-介绍自己" aria-label="Permalink to &quot;🏢 02 介绍自己&quot;">​</a></h2><p class="tc-body" style="font-size:14px;line-height:1.8;"> 这个步骤的重点在于让对方认识我们，消除对方对我们的戒心，进而拉近彼此的距离。也就是告诉客户：我们从哪儿来，来做什么——说明来意。 </p><div class="tc-grid tc-grid-auto" style="margin-top:15px;"><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">✨ 一、简单</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> Simple is good（简单就是好）不要太冗长的介绍你自己，只要简短的介绍即可，可运用你来自附近地区的公司，既简单又容易拉近关系。 </p></div><div class="tc-card tc-card-green"><p class="tc-title tc-green">📢 二、清楚</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 要清楚的告诉对方我们从哪儿来，不要口齿不清而致使对方害怕或排斥。 </p></div><div class="tc-card tc-card-orange"><p class="tc-title tc-orange">💪 三、自信</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 用你的信心让客户相信你所说的一切都是真实的。 </p></div></div><p class="tc-body" style="font-size:14px;line-height:1.8;margin-top:15px;"> 这一步骤决定着你与客户间关系的建立，也是他是否相信你甚至进一步的接受你的一大关键。要运用一些小技巧来拉近彼此的距离，消除对方的心防。 </p><div class="tc-container tc-container-green" style="margin-top:15px;"><p class="tc-subtitle tc-green">📍 打哪来</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 我们是 &gt;&gt; 附近的公司 &gt;&gt; 前面的公司 &gt;&gt; 刚搬过来的公司 &gt;&gt; 隔壁的公司 </p></div><div class="tc-container tc-container-orange" style="margin-top:15px;"><p class="tc-subtitle tc-orange">🎯 做什么</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 今天在我们这小区（这条路、这大楼、这单位）做回馈顾客 &gt;&gt; 周年庆 &gt;&gt; 清仓 &gt;&gt; 广告 &gt;&gt; 要回去了 &gt;&gt; 要下班了 &gt;&gt; 送货来这附近 &gt;&gt; 优惠 &gt;&gt; 回馈（庆祝上市销售突破10万pcs） </p></div><div class="tc-alert tc-alert-red" style="margin-top:15px;"><p class="tc-body tc-sm" style="margin:0;"><strong>⚠️ 注意：</strong>最重要的是要让顾客明白你从哪里来，来做什么，你所说的话要让顾客感觉到听你说完后就会有便宜可占或有好处可拿。否则顾客很可能不会花时间听你继续说下去，而如果这样的话，你的五步就会中途夭折。但介绍自己的过程以简单为好。 </p></div><hr><h2 id="🏢-03-介绍产品" tabindex="-1">🏢 03 介绍产品 <a class="header-anchor" href="#🏢-03-介绍产品" aria-label="Permalink to &quot;🏢 03 介绍产品&quot;">​</a></h2><div class="tc-container tc-container-blue" style="margin-top:15px;"><p class="tc-body" style="font-size:14px;line-height:1.8;margin:0;"> 完成前两步后，这一步要<strong class="tc-blue">简洁有力</strong>。产品是大部分人需要的，争取时间推广特色与优点，让顾客场景化地联想到拥有产品后的美好感受。用力推广价格！ </p></div><div class="tc-grid tc-grid-auto" style="margin-top:15px;"><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">🤝 一、把产品放在他的手上</p><div class="tc-flex tc-flex-col" style="gap:6px;"><span class="tc-item tc-item-blue tc-body tc-sm">&quot;这个给您看一下，很多人都拿了，拿完就没有了&quot;</span><span class="tc-item tc-item-blue tc-body tc-sm">→ 把产品推到他的手边，轻轻碰碰他的手</span><span class="tc-item tc-item-blue tc-body tc-sm">→ 用极自信和亲切的笑容看着他</span><span class="tc-item tc-item-blue tc-body tc-sm">→ 目的：让他有参与感，觉得产品已属于他</span></div></div><div class="tc-card tc-card-green"><p class="tc-title tc-green">💰 二、强调价格</p><div class="tc-flex tc-flex-col" style="gap:6px;"><span class="tc-item tc-item-green tc-body tc-sm">简单介绍特色及优点后，<strong>重点放在价格上</strong></span><span class="tc-item tc-item-green tc-body tc-sm">→ &quot;一般商场要多少钱，今天做活动只要成本价多少&quot;</span><span class="tc-item tc-item-green tc-body tc-sm">→ 给一个便宜的理由：要下班了 / 快卖完了 / 下雨了</span><span class="tc-item tc-item-green tc-body tc-sm">→ &quot;今天带200个来只剩最后几个了，拿完就没有了&quot;</span></div></div><div class="tc-card tc-card-orange"><p class="tc-title tc-orange">🔥 三、制造紧迫感</p><div class="tc-flex tc-flex-col" style="gap:6px;"><span class="tc-item tc-item-orange tc-body tc-sm">&quot;数量有限，用登记的方式，下午送货&quot;</span><span class="tc-item tc-item-orange tc-body tc-sm">→ &quot;现在登记不需要任何订金&quot;</span><span class="tc-item tc-item-orange tc-body tc-sm">→ &quot;很多人都是拿去送人的，自己用也可以送人&quot;</span><span class="tc-item tc-item-orange tc-body tc-sm">→ 实在太便宜了，便宜的吓死人！</span></div></div></div><hr><h2 id="📌-04-成交" tabindex="-1">📌 04 成交 <a class="header-anchor" href="#📌-04-成交" aria-label="Permalink to &quot;📌 04 成交&quot;">​</a></h2><p class="tc-body" style="font-size:14px;line-height:1.8;"> 当敲完价格与递完产品后，这时也是他最兴奋的时候，不要怀疑赶紧做成交，因为这时是他最有冲动想购买的时机，错过了这个时机点，他就会开始思考一些负面（例如：家里很多了、用不到、好像不太好......）。成交时要特别注意的是自己的信心和气势，给他一股紧迫感，更大的肢体动作等等。当然并不是说一定要叫他买，只是这样会增加成功的几率。 </p><div class="tc-grid tc-grid-auto" style="margin-top:15px;"><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">✅ 一、假设</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 他要买 </p></div><div class="tc-card tc-card-green"><p class="tc-title tc-green">❓ 二、问题：二选一法则</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-green tc-body tc-sm">1.&quot;您要送人还是自己用？&quot;</span><span class="tc-item tc-item-green tc-body tc-sm">2.&quot;您拿一套还是两套呢（三套还是四套、一箱还是两箱）&quot;</span><span class="tc-item tc-item-green tc-body tc-sm">3.&quot;您拿50块的还是给我100块呢？&quot;</span><span class="tc-item tc-item-green tc-body tc-sm">4.&quot;您是就要这一套，还是拿一套新的给您？&quot;</span><span class="tc-item tc-item-green tc-body tc-sm">5.&quot;您是现在就用，还是拿回家充足电再用？&quot;</span><span class="tc-item tc-item-green tc-body tc-sm">6.&quot;帮您放哪里呢，还是帮您放这里好了？&quot;</span><span class="tc-item tc-item-green tc-body tc-sm">7.&quot;这是质保单，您看日期写今天的呢，还是帮您写明天的？&quot;</span><span class="tc-item tc-item-green tc-body tc-sm">8.&quot;之后有什么不清楚的，或者还有亲戚朋友需要的话随时可以找我。您看我是留个电话给您，还是加您的微信？&quot;</span></div></div></div><blockquote class="tc-quote tc-quote-blue tc-body" style="margin-top:15px;"><strong>💡 切记：</strong>每当解决完客户的问题时要记得马上做成交。一方面可控制场面，另一方面也可以节省时间避免与客人纠缠。别忘了，当你越是觉得对方会买就越是要快一点做成交，强势而又主动的成交才会让那一些犹豫不决可买可不买的客户下定决定购买，同时也别忘了在给对方成交的问题时要配合上一些肢体语言——动作，越是夸张的肢体动作越能吸引客户的注意及制造乐趣效果，也会对你的成交更有帮助。 </blockquote><div class="tc-container tc-container-orange" style="margin-top:15px;"><p class="tc-subtitle tc-orange">💪 肢体动作的重要性</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 很多人不知道自己在成交客户的过程中为什么会失败，其实有些时候是你自己出卖了自己，因为你的肢体动作表达出来的信号就是没有给自己足够的信心，那客户如何对你充满信心呢？ </p><p class="tc-body" style="font-size:14px;line-height:1.7;margin-top:10px;"> 如果你现在做垂头丧气的动作，这个时候你能不能讲出一些慷慨激昂的事情？你能不能想出什么光芒万丈的语言？你能不能有无与伦比的斗志？ </p><p class="tc-body" style="font-size:14px;line-height:1.7;margin-top:10px;"> 现在可以做一下昂首挺胸的动作，有没有感觉到自己的自信心在提升？所以，你现在把头扬起来，想一个很难过的事情哭出来，你想的起来吗？是的，哪怕哭都要扬头笑着哭，这才是真正的激情！这就是肢体动作的重要性！ </p><p class="tc-body" style="font-size:14px;line-height:1.7;margin-top:10px;"> 你的头一定要保持扬起的状态，昂首就是挺胸。想痛苦想自杀，只要把头抬高，就不怎么想死了；你把头放得低低的，低头一看是悬崖，一不小心没站稳就掉下去了。 </p><p class="tc-body" style="font-size:14px;line-height:1.7;margin-top:10px;"> 所以从现在开始，你要决定自己的所有肢体动作都放在正面的地方，所有的肢体动作都是积极、成功的暗示，这就是一个成功的开始，因为绝大多数人都会被积极的、有自信的人所吸引！ </p></div><div class="tc-container tc-container-blue" style="margin-top:15px;"><p class="tc-subtitle tc-blue">📝 Note</p><div style="display:flex;flex-direction:column;gap:10px;"><p class="tc-body tc-sm">(1) 做成交时，眼睛要与客户相视，脸上露着自信肯定的微笑，并边点头问对方问题。</p><p class="tc-body tc-sm">(2) 给客户购买的理由——创造需求</p><div><p class="tc-body tc-sm">(3) 成交后的动作</p><div style="display:flex;flex-direction:column;gap:6px;margin-top:6px;padding-left:15px;"><p class="tc-body tc-sm">· <strong>恭喜：</strong>成交后千万不要说谢谢，否则他会以为你赚了他很多钱。（*总，恭喜您做了一个明智的决定）</p><p class="tc-body tc-sm">· <strong>转介绍：</strong>立即要求转介绍，这是最好要客户的时机。（*总，您身边有没有哪些像您这么爱学习的朋友呢？）</p><p class="tc-body tc-sm">· <strong>Hustle走人：</strong>既不能走得太快也不能走得太慢，要走的自然，走的合理。既不要留给客户收完钱就跑的感觉，也不要给客户这样的感觉：钱都给你了，你还赖在这里干什么？（*总，您也挺忙的，我就不多打扰你了，回头再联系。）</p></div></div></div></div><hr><h2 id="📌-05-再成交" tabindex="-1">📌 05 再成交 <a class="header-anchor" href="#📌-05-再成交" aria-label="Permalink to &quot;📌 05 再成交&quot;">​</a></h2><div class="tc-container tc-container-blue" style="margin-top:15px;"><p class="tc-body" style="font-size:14px;line-height:1.8;margin:0;"> 在顾客已购买的基础上<strong class="tc-blue">再一次成交</strong>。同一个顾客再成交的套数可能是一套或多套，这是资源的再次利用。成交后<strong class="tc-red">绝对不要立马走人</strong>，要把第一次成交当成导火线，引爆周围！ </p></div><div class="tc-grid tc-grid-auto" style="margin-top:15px;"><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">1️⃣ 模拟订单再成交</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 当你成交完收到钱，你可以利用模拟订单拿给顾客看，指着那个单：&quot;X先生，您看，前面那个王先生本来也和您一样是定一套的，结果送过去以后他看了觉得很好，又这么便宜，一下就拿了三套，说是这么便宜多拿几个去乡下老家送亲戚朋友（或者拿去送客户），又大方又显高档，这样吧，本来是不够货的，但看您人这么好，多给您准备几套拿去送人吧，又省钱又有面子，您看是拿3套还是5套？这样，你也不要拿太多，拿3个先，用的好就帮我做做宣传！没问题吧？&quot;（同时把产品递到客户手中） </p></div><div class="tc-card tc-card-green"><p class="tc-title tc-green">2️⃣ 周围人群成交</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 还有别忘了成交那位顾客周围那些人，有可能的话，这些人一个都不要放过，因为这些人的成交是最容易的，你只需要去每一个都问遍：&quot;先生，（靓女，给您男朋友和老爸一人准备一个吧）您看，你们办公室XXX人都拿了，（也是送老爸的）其他人都准备要拿，您要就赶紧，不然手慢就没有了，看您胡子长得那么性感，（看您长得那么漂亮）这样，先帮您准备两个吧&quot;（同时把产品递到客户手中）。 </p></div><div class="tc-card tc-card-orange"><p class="tc-title tc-orange">3️⃣ 产品品种再成交</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 最后记得对产品品种的再成交。通常情况，我们每张广告单都有两面。也就说至少有两款产品，甚至有的还有三到四款产品。当我们成交其中一款产品之后，一定不要放弃对其它产品的介绍。因为对于已经成交的顾客来说，他已经接纳你这个人了，只需再次接纳你所推荐的产品，比重新找一个顾客要容易的多。 </p></div></div><div class="tc-alert tc-alert-red" style="margin-top:15px;"><p class="tc-body tc-sm" style="margin:0;"><strong>⚠️ Note：</strong>我们的生意就是开口就有，不问就没有，不要预设立场，你不问怎么知道那个人不会多购买你几套？说不定对方想多买几套，可是又不好意思问你，你又不多问一句，你岂不是和钱过不去？反正多问一句又不会亏本，何乐而不为？ </p></div>',35)])])}const y=c(i,[["render",l]]);export{g as __pageData,y as default};
